const QBY = { ar: QAR, en: QEN, tr: QTR, ur: QUR, ms: QMS, fr: QFR, fa: QFA, bn: QBN, hi: QHI };
const QCOUNT = 5;

function shuffleArr(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

